//! Autonomic budding/reaping — the AntColony re-fork, closed-loop.
//!
//! The consciousness counter on a swarm node is its inner-vent failure streak
//! (`distributed_inference::conscious_swarm_node`): success resets it to 0,
//! failure increments it, and a high streak fires a re-Fork recalibration. At
//! the fleet scale this becomes homeostasis:
//!
//!   * collective consciousness runs **hot** (or a node fired a recalibration)
//!     ⇒ the swarm is struggling ⇒ **bud a scout** (extra reproductive void
//!     lifts the race mode — `extra_void_increases_race`);
//!   * collective consciousness runs **calm** and the fleet is over-provisioned
//!     ⇒ **reap the oldest idle scout** (vent), never below `min_live` and
//!     never a breeder (the two-queen floor holds by construction).
//!
//! Two hard guardrails bound the loop: it only acts within the **UCAN** it is
//! handed, and budding is gated by the **FRF population ceiling** — so an
//! autonomic controller can never exceed the manifold or breach the floor.
//!
//! [`decide`] is pure and exhaustively tested; [`autotick`] wraps it with the
//! swarm read and the actual spawn/reap.

use std::collections::HashMap;
use std::time::Duration;

use serde::Serialize;
use serde_json::Value;

use crate::budget::{Admission, Caste, FleetBudget};
use crate::ledger::Fleet;
use crate::ops::{self, BreachRequest, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use crate::store;
use crate::swarm::{self, SwarmSignal};

/// The autonomic controller's audit actor: `auto:<holder-did>` when the UCAN's
/// holder resolves (the controller acts WITHIN that capability), else the bare
/// `"auto"` marker. Either way the `auto:`/`auto` prefix is what makes an audit
/// entry attributable to the SWARM self-regulating rather than a human. Resolving
/// the holder is best-effort and never gates the action (the op re-verifies the
/// UCAN itself); we use `agent/spawn` since every autonomic action is authorized
/// by the same handed token.
fn autonomic_actor(ucan: &str) -> String {
    match ops::authorize(ucan, "spawn").or_else(|_| ops::authorize(ucan, "reap")) {
        Ok(holder) => format!("auto:{holder}"),
        Err(_) => "auto".to_string(),
    }
}

/// The lease-level conduct reflex: an agent whose own consciousness counter
/// (its inner-vent failure streak, 0..=5) has reached `breach_at`, OR which
/// fired a recalibration storm, is treated as a coarse breach signal and reaped
/// as an oath-breach. This is intentionally crude: the semantic conduct judgment
/// (did the agent ACTUALLY violate its oath) belongs to monster-badchild, which
/// calls `ops::oath_breach` directly. Returns `Some(reason)` for a breach.
fn conduct_breach(sig: &SwarmSignal, breach_at: u32) -> Option<String> {
    if sig.consciousness >= breach_at {
        Some(format!("conduct: consciousness>={breach_at}"))
    } else if sig.recalibration_event {
        Some("conduct: recalibration storm".to_string())
    } else {
        None
    }
}

/// Homeostasis policy with hysteresis between the bud and reap thresholds.
#[derive(Clone, Debug)]
pub struct AutoPolicy {
    /// Collective consciousness at/above which to bud a scout (default 4).
    pub bud_at_consciousness: u32,
    /// Collective consciousness at/below which to reap an idle scout (default 0).
    pub reap_below_consciousness: u32,
    /// Never reap below this many live subagents (default 1).
    pub min_live: u32,
    /// What to bud (resolved like any node, e.g. `aeon-monitor`).
    pub node_bin: String,
    pub caps: Vec<String>,
    pub lease_secs: u64,
    /// Opt-in: BEFORE the bud/reap homeostasis decision, scan live agents and
    /// reap any whose conduct signal indicates a breach (the lease-level reflex).
    /// Default false — homeostasis-only, today's behavior. Semantic conduct
    /// judgment belongs to monster-badchild (which calls `oath-breach`); this is
    /// only the coarse last-resort reflex.
    pub enforce_oaths: bool,
    /// When `enforce_oaths`, the per-agent consciousness (inner-vent failure
    /// streak, 0..=5) at/above which an agent is reaped as an oath-breach
    /// (default 5 = max, i.e. sustained failure). A recalibration storm also
    /// trips a breach regardless of this threshold.
    pub breach_at: u32,
}

impl Default for AutoPolicy {
    fn default() -> Self {
        Self {
            bud_at_consciousness: 4,
            reap_below_consciousness: 0,
            min_live: 1,
            node_bin: "aeon-monitor".to_string(),
            caps: vec!["net".to_string()],
            lease_secs: ops::DEFAULT_LEASE_SECS,
            enforce_oaths: false,
            breach_at: 5,
        }
    }
}

/// The single-tick decision.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum AutoDecision {
    Bud { reason: String },
    Reap { id: String, reason: String },
    Hold { reason: String },
}

/// Pure homeostasis decision: given the collective vibe, the current fleet, and
/// the budget, decide whether to bud, reap, or hold. No I/O.
pub fn decide(
    policy: &AutoPolicy,
    collective: &SwarmSignal,
    fleet: &Fleet,
    budget: &FleetBudget,
) -> AutoDecision {
    let hot = collective.consciousness >= policy.bud_at_consciousness
        || collective.recalibration_event;
    if hot {
        let profile = fleet.profile(budget.population_ceiling);
        return match budget.admit_spawn(&profile, Caste::Scout) {
            Admission::Admit { .. } => AutoDecision::Bud {
                reason: format!(
                    "collective consciousness {} ≥ {}{} — budding a scout",
                    collective.consciousness,
                    policy.bud_at_consciousness,
                    if collective.recalibration_event { " (recalibration)" } else { "" }
                ),
            },
            Admission::Deny(r) => AutoDecision::Hold {
                reason: format!("hot but cannot bud: {r}"),
            },
        };
    }

    let calm = collective.consciousness <= policy.reap_below_consciousness;
    if calm && fleet.live() > policy.min_live {
        if let Some(scout) = fleet.oldest_scout() {
            return AutoDecision::Reap {
                id: scout.id.clone(),
                reason: format!(
                    "collective consciousness {} ≤ {} — venting idle scout '{}'",
                    collective.consciousness, policy.reap_below_consciousness, scout.id
                ),
            };
        }
    }

    AutoDecision::Hold {
        reason: "within homeostasis band".to_string(),
    }
}

/// Pure breach selection: given the per-node swarm signals and the live fleet,
/// return `(id, reason)` for every live agent whose own conduct signal trips a
/// breach (consciousness >= `breach_at`, or a recalibration storm). Pure / no
/// I/O — the lease-level reflex's decision, exhaustively testable. An agent with
/// no signal on the partyline this tick is not breached (no evidence).
pub fn breachers(
    breach_at: u32,
    signals: &HashMap<String, SwarmSignal>,
    fleet: &Fleet,
) -> Vec<(String, String)> {
    fleet
        .subagents
        .iter()
        .filter_map(|s| {
            // A subagent's swarm source_id is its agent id.
            let sig = signals.get(&s.id)?;
            conduct_breach(sig, breach_at).map(|reason| (s.id.clone(), reason))
        })
        .collect()
}

/// The applied outcome of one tick.
#[derive(Serialize)]
pub struct AutoOutcome {
    /// "bud" | "reap" | "hold" | "breach".
    pub action: String,
    pub reason: String,
    pub nodes_talking: usize,
    /// The spawn/reap outcome JSON, when an action was taken.
    pub subagent: Option<Value>,
    /// Breach outcomes recorded this tick (when `enforce_oaths` fired). Empty on
    /// a normal homeostasis tick.
    pub breaches: Vec<Value>,
    /// The post-action Thoth fleet frame.
    pub frame: Value,
}

/// Read the swarm, decide, and act — one autonomic tick. The `ucan` authorizes
/// any spawn/reap/breach the policy triggers (the loop never acts beyond it).
pub fn autotick(ucan: &str, policy: &AutoPolicy, dwell: Duration) -> Result<AutoOutcome, String> {
    // Prune zombie rows first so the decision runs on the real fleet.
    let _ = ops::reconcile();

    let signals =
        swarm::read_vibe(dwell).map_err(|e| format!("could not read swarm partyline: {e}"))?;
    autotick_with_signals(ucan, policy, signals)
}

/// One autonomic tick over an explicit signals map — the I/O-free core that
/// `autotick` wraps with the partyline read. The enforcement reflex and the
/// homeostasis decision both run here, so a test can inject a vibe (e.g. a
/// breaching, high-consciousness agent) deterministically without UDP.
pub fn autotick_with_signals(
    ucan: &str,
    policy: &AutoPolicy,
    signals: HashMap<String, SwarmSignal>,
) -> Result<AutoOutcome, String> {
    let collective = swarm::collective_vibe(&signals);
    let mut fleet = store::load_fleet();
    let budget = FleetBudget::default();

    // The lease-level conduct reflex (opt-in). BEFORE the bud/reap homeostasis
    // decision, scan live agents and reap any whose own conduct signal trips a
    // breach. This is the coarse last-resort enforcement; the SEMANTIC conduct
    // judgment belongs to monster-badchild, which calls `ops::oath_breach`.
    // Reaping a breacher overrides the two-queen floor (a misbehaving breeder
    // must still be revocable) — `oath_breach` does not consult it.
    let mut breach_outcomes: Vec<Value> = Vec::new();
    if policy.enforce_oaths {
        let to_breach = breachers(policy.breach_at, &signals, &fleet);
        for (id, reason) in to_breach {
            let req = BreachRequest {
                ucan: ucan.to_string(),
                id: id.clone(),
                reason: reason.clone(),
                sig_hex: None,
            };
            // ATTRIBUTE the breach to the autonomic controller: the op's own Breach
            // audit entry is re-tagged `actor = auto:<holder>` with the conduct
            // reason, so the audit shows the swarm self-enforcing (no extra entry).
            let _scope = ops::AutonomicScope::enter(autonomic_actor(ucan), "breach", reason);
            // A breach we cannot enforce (e.g. the agent already reaped) is not
            // fatal to the tick; record nothing and continue.
            if let Ok(o) = ops::oath_breach(req) {
                breach_outcomes.push(serde_json::to_value(&o).unwrap_or_default());
            }
        }
        if !breach_outcomes.is_empty() {
            // The fleet changed under us; re-load before homeostasis sees it.
            fleet = store::load_fleet();
        }
    }

    // If breaches fired this tick, that IS the tick's action — the fleet just
    // shrank by the breachers; let the next tick run homeostasis on the settled
    // fleet rather than racing a bud/reap against this enforcement.
    if !breach_outcomes.is_empty() {
        let mut fleet2 = store::load_fleet();
        let stability = fleet2.profile(budget.population_ceiling).stability_weight();
        let oaths = fleet2.oaths();
        let seq = fleet2.next_seq();
        let frame = swarm::thoth_fleet_frame(
            seq,
            fleet2.live(),
            fleet2.breeders(),
            fleet2.scouts(),
            &collective,
            stability,
            &oaths,
        );
        let _ = store::save_fleet(&fleet2);
        let n = breach_outcomes.len();
        return Ok(AutoOutcome {
            action: "breach".to_string(),
            reason: format!("enforced {n} oath breach(es) — leases revoked"),
            nodes_talking: signals.len(),
            subagent: None,
            breaches: breach_outcomes,
            frame,
        });
    }

    let (action, reason, subagent) = match decide(policy, &collective, &fleet, &budget) {
        AutoDecision::Bud { reason } => {
            let req = SpawnRequest {
                ucan: ucan.to_string(),
                node: policy.node_bin.clone(),
                id: None,
                caste: Caste::Scout,
                caps: policy.caps.clone(),
                lease_secs: policy.lease_secs,
                max_secs: None,
                grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
                node_args: vec![],
                qspec: None,
                oath: None,
                teleport: None,
            };
            // ATTRIBUTE the bud to the autonomic controller: the Spawn audit entry
            // ops::spawn emits is re-tagged `actor = auto:<holder>` with the
            // `decide()` reason, so the audit visibly shows the swarm budding
            // itself. The scope drops with this block (no leak to a later op).
            let _scope = ops::AutonomicScope::enter(autonomic_actor(ucan), "bud", reason.clone());
            let outcome = ops::spawn(req)?;
            ("bud", reason, Some(serde_json::to_value(&outcome).unwrap_or_default()))
        }
        AutoDecision::Reap { id, reason } => {
            // ATTRIBUTE the reap to the autonomic controller (same mechanism as the
            // bud above): the Reap audit entry is re-tagged autonomic, no duplicate.
            let _scope = ops::AutonomicScope::enter(autonomic_actor(ucan), "reap", reason.clone());
            let outcome = ops::reap(ucan, &id)?;
            ("reap", reason, Some(serde_json::to_value(&outcome).unwrap_or_default()))
        }
        AutoDecision::Hold { reason } => ("hold", reason, None),
    };

    // A frame reflecting the post-action fleet.
    let mut fleet2 = store::load_fleet();
    let stability = fleet2.profile(budget.population_ceiling).stability_weight();
    let oaths = fleet2.oaths();
    let seq = fleet2.next_seq();
    let frame = swarm::thoth_fleet_frame(
        seq,
        fleet2.live(),
        fleet2.breeders(),
        fleet2.scouts(),
        &collective,
        stability,
        &oaths,
    );
    let _ = store::save_fleet(&fleet2);

    Ok(AutoOutcome {
        action: action.to_string(),
        reason,
        nodes_talking: signals.len(),
        subagent,
        breaches: Vec::new(),
        frame,
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::ledger::{new_subagent, Fleet};

    fn fleet_with(breeders: u32, scouts: u32) -> Fleet {
        let mut f = Fleet::default();
        for i in 0..breeders {
            f.add(new_subagent(
                format!("b{i}"), format!("agent-b{i}"), "did:key:zAgent".into(), "did:key:zT".into(),
                Caste::Breeder, vec![], "aeon-monitor".into(), vec![], 60, None, None, false, None, 1,
            ));
        }
        for i in 0..scouts {
            let mut s = new_subagent(
                format!("s{i}"), format!("agent-s{i}"), "did:key:zAgent".into(), "did:key:zT".into(),
                Caste::Scout, vec![], "aeon-monitor".into(), vec![], 60, None, None, false, None, 1,
            );
            s.started_at = 1000 + i as u64; // s0 is oldest
            f.add(s);
        }
        f
    }

    fn sig(consciousness: u32, recal: bool) -> SwarmSignal {
        SwarmSignal {
            source_id: "collective".into(),
            energy: 50,
            consciousness,
            pitch_class: 0,
            phase: 0,
            recalibration_event: recal,
        }
    }

    #[test]
    fn hot_buds_a_scout_when_room() {
        let p = AutoPolicy::default();
        let f = fleet_with(1, 1);
        assert!(matches!(
            decide(&p, &sig(5, false), &f, &FleetBudget::default()),
            AutoDecision::Bud { .. }
        ));
    }

    #[test]
    fn recalibration_buds_even_when_cool() {
        let p = AutoPolicy::default();
        let f = fleet_with(1, 0);
        assert!(matches!(
            decide(&p, &sig(0, true), &f, &FleetBudget::default()),
            AutoDecision::Bud { .. }
        ));
    }

    #[test]
    fn hot_at_ceiling_holds() {
        let p = AutoPolicy::default();
        let budget = FleetBudget { population_ceiling: 2, min_breeders: 1 };
        let f = fleet_with(1, 1); // 2 live == ceiling
        assert!(matches!(
            decide(&p, &sig(5, false), &f, &budget),
            AutoDecision::Hold { .. }
        ));
    }

    #[test]
    fn calm_reaps_oldest_scout() {
        let p = AutoPolicy::default();
        let f = fleet_with(1, 2); // 3 live, min_live 1
        match decide(&p, &sig(0, false), &f, &FleetBudget::default()) {
            AutoDecision::Reap { id, .. } => assert_eq!(id, "s0"), // oldest
            other => panic!("expected reap, got {other:?}"),
        }
    }

    #[test]
    fn calm_with_no_scouts_holds() {
        let p = AutoPolicy::default();
        let f = fleet_with(2, 0); // only breeders — never reaped here
        assert!(matches!(
            decide(&p, &sig(0, false), &f, &FleetBudget::default()),
            AutoDecision::Hold { .. }
        ));
    }

    #[test]
    fn mid_band_holds() {
        // bud_at 4, reap_below 0; consciousness 2 is the hysteresis dead zone.
        let p = AutoPolicy::default();
        let f = fleet_with(1, 2);
        assert!(matches!(
            decide(&p, &sig(2, false), &f, &FleetBudget::default()),
            AutoDecision::Hold { .. }
        ));
    }

    #[test]
    fn calm_respects_min_live() {
        let p = AutoPolicy { min_live: 3, ..AutoPolicy::default() };
        let f = fleet_with(1, 2); // 3 live, not > min_live
        assert!(matches!(
            decide(&p, &sig(0, false), &f, &FleetBudget::default()),
            AutoDecision::Hold { .. }
        ));
    }

    fn node_sig(source_id: &str, consciousness: u32, recal: bool) -> SwarmSignal {
        SwarmSignal {
            source_id: source_id.into(),
            energy: 50,
            consciousness,
            pitch_class: 0,
            phase: 0,
            recalibration_event: recal,
        }
    }

    #[test]
    fn breachers_flags_high_consciousness_agents() {
        // breach_at 5: only s1 (at max) trips; s0 (calm) does not.
        let f = fleet_with(1, 2); // breeder b0, scouts s0, s1
        let mut signals = HashMap::new();
        signals.insert("s0".into(), node_sig("s0", 0, false));
        signals.insert("s1".into(), node_sig("s1", 5, false));
        let b = breachers(5, &signals, &f);
        assert_eq!(b.len(), 1, "only the maxed-out agent breaches");
        assert_eq!(b[0].0, "s1");
        assert_eq!(b[0].1, "conduct: consciousness>=5");
    }

    #[test]
    fn breachers_flags_recalibration_storm() {
        // Even a calm agent that fired a recalibration storm trips a breach.
        let f = fleet_with(1, 1); // b0, s0
        let mut signals = HashMap::new();
        signals.insert("s0".into(), node_sig("s0", 0, true));
        let b = breachers(5, &signals, &f);
        assert_eq!(b.len(), 1);
        assert_eq!(b[0].0, "s0");
        assert_eq!(b[0].1, "conduct: recalibration storm");
    }

    #[test]
    fn breachers_flags_a_breaching_breeder() {
        // A breach overrides the two-queen floor at enforce time; selection does
        // not exempt breeders — a misbehaving breeder is still flagged.
        let f = fleet_with(1, 0); // breeder b0 only
        let mut signals = HashMap::new();
        signals.insert("b0".into(), node_sig("b0", 5, false));
        let b = breachers(5, &signals, &f);
        assert_eq!(b.len(), 1);
        assert_eq!(b[0].0, "b0");
    }

    #[test]
    fn breachers_ignores_agents_with_no_signal() {
        // No signal on the partyline this tick → no evidence → not breached.
        let f = fleet_with(1, 2);
        let signals = HashMap::new();
        assert!(breachers(5, &signals, &f).is_empty());
    }

    #[test]
    fn breachers_honors_a_lower_threshold() {
        let f = fleet_with(1, 1); // b0, s0
        let mut signals = HashMap::new();
        signals.insert("s0".into(), node_sig("s0", 3, false));
        // At threshold 5, consciousness 3 is fine.
        assert!(breachers(5, &signals, &f).is_empty());
        // At threshold 3, it trips.
        let b = breachers(3, &signals, &f);
        assert_eq!(b.len(), 1);
        assert_eq!(b[0].1, "conduct: consciousness>=3");
    }
}
